1	import { describe, it, expect } from "vitest";
2	import { quote, claim } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // ===== QUOTE: simplest cases =====
6	  describe("quote — empty and edge cases", () => {
7	    it.todo("empty item list returns premium 5 G (only the processing fee)");
8	  });
9	
10	  // ===== QUOTE: single main items, base premiums + first-insurance + fee =====
11	  describe("quote — single main items (newcomer, plain)", () => {
12	    it.todo("plain sword for a newcomer first insurance returns 115 G (100 base + 10 first-insurance + 5 fee)");
13	    it.todo("plain amulet for a newcomer first insurance returns 71 G (60 base + 6 first-insurance + 5 fee)");
14	    it.todo("plain staff for a newcomer first insurance returns 93 G (80 base + 8 first-insurance + 5 fee)");
15	    it.todo("plain potion for a newcomer first insurance returns 49 G (40 base + 4 first-insurance + 5 fee)");
16	  });
17	
18	  // ===== QUOTE: components (runes, moonstones) =====
19	  describe("quote — components and building blocks", () => {
20	    it.todo("2 runes base premium is 50 G (2 × 25, no block)");
21	    it.todo("3 runes base premium is 60 G (block discount applies)");
22	    it.todo("4 runes base premium is 100 G (4 × 25, no block — block requires exactly 3)");
23	    it.todo("7 runes base premium is 175 G (7 × 25, no block formed across 3+3+1)");
24	    it.todo("2 runes + 1 moonstone base premium is 75 G (no block: different types)");
25	    it.todo("3 runes + 3 moonstones base premium is 120 G (two separate blocks of 60 G each)");
26	  });
27	
28	  // ===== QUOTE: item-specific modifiers =====
29	  describe("quote — item-specific modifiers (cursed, high enchantment)", () => {
30	    it.todo("cursed sword (enchantment 3) for newcomer returns 165 G (100 base + 50 curse + 10 first-insurance + 5 fee)");
31	    it.todo("sword with exactly enchantment 5 gets the high-enchantment surcharge");
32	    it.todo("sword with enchantment 4 does NOT get the high-enchantment surcharge");
33	    it.todo("cursed sword with enchantment 5 gets BOTH cursed and high-enchantment surcharges");
34	  });
35	
36	  // ===== QUOTE: modifier scope on multi-item policies =====
37	  describe("quote — modifier scope on multi-item policies", () => {
38	    it.todo("policy with cursed sword + plain amulet has policy base premium 160 G; cursed adds 50 G (50% of cursed sword's base) → 210 G before policy modifiers and fee");
39	  });
40	
41	  // ===== QUOTE: policy-wide modifiers (loyalty, first-insurance, follow-up) =====
42	  describe("quote — policy-wide modifiers", () => {
43	    it.todo("customer with exactly 2 years with MHPCO gets the 20% loyalty discount");
44	    it.todo("customer with less than 2 years does NOT get the loyalty discount");
45	    it.todo("follow-up contract (customer's second quote in scenario) gets the 15% discount");
46	    it.todo("each new item in a quote is treated as a first insurance regardless of customer history");
47	  });
48	
49	  // ===== QUOTE: rounding =====
50	  describe("quote — rounding", () => {
51	    it.todo("premium calculation yielding 197.5 G rounds UP to 198 G (in MHPCO's favor)");
52	    it.todo("intermediate amounts are kept as fractions; only the final premium is rounded");
53	  });
54	
55	  // ===== QUOTE: integration examples =====
56	  describe("quote — integration examples", () => {
57	    it.todo("newcomer (0 years, no previous contract) with cursed sword (steel, enchantment 3) → premium 165 G");
58	    it.todo("3-year customer's second quote with cursed sword (steel, enchantment 7) → premium 160 G (100 base + 50 curse + 30 high-enchant − 20 loyalty + 10 first-insurance − 15 follow-up + 5 fee)");
59	  });
60	
61	  // ===== QUOTE: errors =====
62	  describe("quote — errors", () => {
63	    it.todo("unknown item type (e.g. broomstick) throws / returns error");
64	  });
65	
66	  // ===== CLAIM: standard reimbursement =====
67	  describe("claim — standard reimbursement (no special clauses)", () => {
68	    it.todo("regular sword (steel, enchantment 3) with damage 500 G → payout 400 G (500 − 100 deductible)");
69	    it.todo("damage to a rune (insurance value 250 G), damage 200 G → payout 100 G (200 − 100 deductible)");
70	  });
71	
72	  // ===== CLAIM: enchantment clause =====
73	  describe("claim — high-enchantment clause (≥8)", () => {
74	    it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50% then 100 deductible)");
75	    it.todo("steel sword, enchantment 8, damage 1000 G → payout 400 G (50% then 100 deductible)");
76	  });
77	
78	  // ===== CLAIM: dragon material clause =====
79	  describe("claim — dragon material clause", () => {
80	    it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (full reimbursement, then 100 deductible)");
81	  });
82	
83	  // ===== CLAIM: dragon vs enchantment precedence =====
84	  describe("claim — dragon vs enchantment precedence (50% rule wins)", () => {
85	    it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (both apply; 50% rule wins, then deductible)");
86	  });
87	
88	  // ===== CLAIM: deductible per damage event =====
89	  describe("claim — deductible per damage event", () => {
90	    it.todo("dragon attack damages sword (500 G) and amulet (300 G) on same policy → payout 600 G (deductible applies once per damaged item)");
91	  });
92	
93	  // ===== CLAIM: multiple items of the same type =====
94	  describe("claim — multiple items of the same type", () => {
95	    it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G");
96	    it.todo("two sword damages on a policy with two swords → each is a separate damage with its own deductible");
97	    it.todo("more sword damages than insured swords → claim rejected (error)");
98	  });
99	
100	  // ===== CLAIM: cap =====
101	  describe("claim — cap calculation and exhaustion", () => {
102	    it.todo("policy with sword + amulet has insurance sum 1600 G and cap 3200 G");
103	    it.todo("cursed sword (premium with modifiers 165 G) has cap 2000 G (based on unmodified insurance value)");
104	    it.todo("policy with sword + 3 runes has insurance sum 1750 G (block discount affects premium only)");
105	    it.todo("sword insured (cap 2000 G), first claim of 1500 G → payout 1400 G, remainingCap 600 G");
106	    it.todo("sword insured (cap 2000 G), after 1400 G payout (cap 600 remaining), second claim of 1500 G → payout 600 G, remainingCap 0 G");
107	  });
108	
109	  // ===== CLAIM: rounding =====
110	  describe("claim — rounding", () => {
111	    it.todo("payout calculation yielding 350.5 G rounds DOWN to 350 G (in MHPCO's favor)");
112	  });
113	
114	  // ===== CLAIM: errors =====
115	  describe("claim — errors", () => {
116	    it.todo("claim references item not in policy (e.g. amulet damage on sword-only policy) → error");
117	    it.todo("claim references an unknown item type → error");
118	    it.todo("claim contains a damage entry with negative amount → error");
119	  });
120	
121	  // ===== Integration: claim on dragon sword with enchantment threshold =====
122	  describe("claim — combined scenarios from spec", () => {
123	    it.todo("dragon-material sword with exactly enchantment 8, damage 1000 G → payout 400 G (high-enchantment clause applies, then deductible)");
124	  });
125	});
126	
127	describe("CLI (claim-office)", () => {
128	  // ===== CLI: basic quote scenarios =====
129	  it.todo("processes a single quote step and writes results array with one premium");
130	  it.todo("processes a scenario with quote followed by claim and writes results in same order");
131	  it.todo("claim step references a prior quote via policy index (zero-based)");
132	  it.todo("processes the schema example (5-year customer, amulet, then claim) producing premium and payout/remainingCap");
133	
134	  // ===== CLI: errors =====
135	  it.todo("quote with unknown item type → exits non-zero, writes error to stderr, no results to stdout");
136	  it.todo("claim referencing item not in policy → exits non-zero, writes error to stderr");
137	  it.todo("claim with negative damage amount → exits non-zero, writes error to stderr");
138	  it.todo("claim with more damages of a type than insured items → exits non-zero, whole claim rejected");
139	
140	  // ===== CLI: multi-step scenarios =====
141	  it.todo("scenario with two successive claims tracks remainingCap across claims");
142	  it.todo("scenario with multiple quote steps treats second quote as follow-up contract with 15% discount");
143	});
